+func countJSONLLines(path string) (int, error) {
+	f, err := os.Open(path)
+	if err != nil {
+		return 0, err
+	}
+	defer f.Close()
+
+	const bufSize = 32 * 1024
+	buf := make([]byte, bufSize)
+	lines := 0
+	sawAny := false
+	lastByte := byte(0)
+
+	for {
+		n, readErr := f.Read(buf)
+		if n > 0 {
+			sawAny = true
+			lastByte = buf[n-1]
+			for _, b := range buf[:n] {
+				if b == '\n' {
+					lines++
+				}
+			}
+		}
+		if readErr == nil {
+			continue
+		}
+		if readErr == io.EOF {
+			break
+		}
+		return 0, readErr
+	}
+
+	if sawAny && lastByte != '\n' {
+		lines++
+	}
+	return lines, nil
+}
